как добавить каскадное удаление для двух таблиц
CREATE TABLE Firms (
firm_id INT PRIMARY KEY NOT NULL,
firm_name VARCHAR(50)
);

CREATE TABLE Computers (
computer_id INT PRIMARY KEY NOT NULL,
frequency NUMBER,
type_name VARCHAR(50),
firm_id INT,
FOREIGN KEY (firm_id) REFERENCES Firms(firm_id)
);

Переделай следующий код под функцию max:
PROCEDURE find_max_frequency_computer(excluded_computer_id INT, computer_data OUT ComputerData) IS
    Cursor cur_freq IS
        SELECT c.computer_id, c.type_name, c.firm_id, c.frequency
        FROM Computers c
        WHERE c.computer_id <> excluded_computer_id
        ORDER BY c.frequency DESC;
    BEGIN
        SAVEPOINT start_transaction;
        OPEN cur_freq;

        BEGIN
            FETCH cur_freq INTO computer_data;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                computer_data := NULL;
        END;

        CLOSE cur_freq;
        COMMIT;
    EXCEPTION 
        WHEN OTHERS THEN
            ROLLBACK TO start_transaction;
            DBMS_OUTPUT.PUT_LINE('find_max_frequency_computer ERROR');
    END find_max_frequency_computer;

Для переделки данного процедурного кода на функцию, которая будет возвращать запись с максимальной частотой (frequency), необходимо изменить его структуру и использовать функцию вместо процедуры. Также следует использовать возвращаемое значение функции вместо параметра OUT.

Вот как можно это сделать:

```sql
CREATE OR REPLACE FUNCTION find_max_frequency_computer(excluded_computer_id INT)
RETURN ComputerData
IS
  max_freq_data ComputerData;

  CURSOR cur_freq IS
    SELECT c.computer_id, c.type_name, c.firm_id, c.frequency
    FROM Computers c
    WHERE c.computer_id <> excluded_computer_id
    ORDER BY c.frequency DESC;

BEGIN
  OPEN cur_freq;

  BEGIN
    FETCH cur_freq INTO max_freq_data;
    IF cur_freq%NOTFOUND THEN
      max_freq_data := NULL;
    END IF;
  END;

  CLOSE cur_freq;
  RETURN max_freq_data;

EXCEPTION
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('find_max_frequency_computer ERROR');
    RETURN NULL; -- При возникновении ошибки возвращаем NULL
END find_max_frequency_computer;
/
```

В данном коде функция `find_max_frequency_computer` возвращает запись с максимальной частотой (frequency) исключая запись с `computer_id` равным параметру `excluded_computer_id`. Если не найдено соответствующих данных, функция вернет NULL.

Пожалуйста, убедитесь, что структура и логика функции соответствуют вашим требованиям и логике вашей базы данных.

Для создания агрегатной функции, которая будет обрабатывать все строки в таблице или результат запроса, можно воспользоваться возможностями PL/SQL и создать свою собственную агрегатную функцию.

Вот пример агрегатной функции, которая будет суммировать значения частоты (frequency) из таблицы Computers:

```sql
CREATE OR REPLACE TYPE SumFrequencyType AS OBJECT (
  total_frequency NUMBER
);

CREATE OR REPLACE TYPE SumFrequencyTypeFinal AS OBJECT (
  total_frequency_final NUMBER
);

CREATE OR REPLACE FUNCTION sum_frequency(input_number NUMBER) RETURN SumFrequencyType AGGREGATE USING SumFrequencyTypeFinal;

CREATE OR REPLACE TYPE BODY SumFrequencyTypeFinal IS
  total_frequency_final NUMBER := 0;

  STATIC FUNCTION ODCIAggregateInitialize(sctx IN OUT SumFrequencyTypeFinal) RETURN NUMBER IS
  BEGIN
    sctx := SumFrequencyTypeFinal(0);
    RETURN ODCIConst.Success;
  END;

  MEMBER FUNCTION ODCIAggregateIterate(self IN OUT SumFrequencyTypeFinal, value IN NUMBER) RETURN NUMBER IS
  BEGIN
    self.total_frequency_final := self.total_frequency_final + value;
    RETURN ODCIConst.Success;
  END;

  MEMBER FUNCTION ODCIAggregateTerminate(self IN SumFrequencyTypeFinal, returnValue OUT NUMBER, flags IN NUMBER) RETURN NUMBER IS
  BEGIN
    returnValue := self.total_frequency_final;
    RETURN ODCIConst.Success;
  END;
END;
/

CREATE OR REPLACE FUNCTION sum_frequency(input_number NUMBER) RETURN SumFrequencyType AGGREGATE USING SumFrequencyTypeFinal;
/

```

В данном примере создается агрегатная функция `sum_frequency`, которая будет суммировать значения частоты (frequency) из таблицы Computers. 

